    <script>
        // DOM Elements
const header = document.querySelector('#header');
const backToTop = document.querySelector('#back-to-top');
const mobileMenuBtn = document.querySelector('#mobile-menu-btn');
const mobileMenu = document.querySelector('#mobile-menu');
// const parallaxProduct = document.querySelector('.parallax-product');
const animatedElements = document.querySelectorAll('.feature-card, .product-details, .specs-group');
const testimonialItems = document.querySelectorAll('.testimonial-item');
const prevBtn = document.querySelector('#prev-btn');
const nextBtn = document.querySelector('#next-btn');
const sliderDots = document.querySelectorAll('#slider-dots button');

// Variables
let currentSlide = 0;
let isScrolling = false;

// Functions
function handleScroll() {
    const scrollPosition = window.scrollY;
    
    // Header styling on scroll
    if (scrollPosition > 50) {
        header.classList.add('shadow-lg');
        header.classList.add('py-2');
        header.classList.remove('py-4');
    } else {
        header.classList.remove('shadow-lg');
        header.classList.remove('py-2');
        header.classList.add('py-4');
    }
    
    // Back to top button visibility
    if (scrollPosition > 500) {
        backToTop.classList.remove('opacity-0', 'invisible');
    } else {
        backToTop.classList.add('opacity-0', 'invisible');
    }
    
    // Parallax effect for product image
        // Parallax effect for product image
        if (parallaxProduct && window.innerWidth > 768) {
        const productSection = parallaxProduct.closest('#product-showcase');
        const productOffset = productSection.offsetTop;
        const scrollRelative = scrollPosition - productOffset + window.innerHeight;
        
        if (scrollRelative > 0 && scrollPosition < productOffset + productSection.offsetHeight) {
            parallaxProduct.style.transform = `translateY(${scrollRelative * 0.05}px)`;
        }
    }
    
    // Animate elements when they come into view
    animatedElements.forEach(element => {
        const elementTop = element.getBoundingClientRect().top;
        const elementBottom = element.getBoundingClientRect().bottom;
        
        if (elementTop < window.innerHeight - 100 && elementBottom > 0) {
            element.classList.add('animate');
        }
    });
}

// Throttle scroll events for better performance
function throttle(callback, delay) {
    let isThrottled = false;
    
    return function() {
        if (isThrottled) return;
        
        isThrottled = true;
        setTimeout(() => {
            callback();
            isThrottled = false;
        }, delay);
    }
}

// Toggle mobile menu
function toggleMobileMenu() {
    const isOpen = mobileMenu.classList.contains('translate-y-0');
    
    if (isOpen) {
        mobileMenu.classList.remove('translate-y-0', 'opacity-100', 'visible');
        mobileMenu.classList.add('-translate-y-full', 'opacity-0', 'invisible');
        mobileMenuBtn.innerHTML = '<i class="fas fa-bars"></i>';
    } else {
        mobileMenu.classList.remove('-translate-y-full', 'opacity-0', 'invisible');
        mobileMenu.classList.add('translate-y-0', 'opacity-100', 'visible');
        mobileMenuBtn.innerHTML = '<i class="fas fa-times"></i>';
    }
}

// Testimonial slider functions
function showSlide(index) {
    testimonialItems.forEach((item, i) => {
        if (i === index) {
            item.classList.remove('hidden');
        } else {
            item.classList.add('hidden');
        }
    });
    
    sliderDots.forEach((dot, i) => {
        if (i === index) {
            dot.classList.add('bg-primary', 'scale-125');
            dot.classList.remove('bg-gray-400');
        } else {
            dot.classList.remove('bg-primary', 'scale-125');
            dot.classList.add('bg-gray-400');
        }
    });
    
    currentSlide = index;
}

function nextSlide() {
    const newIndex = (currentSlide + 1) % testimonialItems.length;
    showSlide(newIndex);
}

function prevSlide() {
    const newIndex = (currentSlide - 1 + testimonialItems.length) % testimonialItems.length;
    showSlide(newIndex);
}

// Event Listeners
window.addEventListener('scroll', throttle(handleScroll, 100));

backToTop.addEventListener('click', () => {
    window.scrollTo({
        top: 0,
        behavior: 'smooth'
    });
});

mobileMenuBtn.addEventListener('click', toggleMobileMenu);

if (prevBtn && nextBtn) {
    prevBtn.addEventListener('click', prevSlide);
    nextBtn.addEventListener('click', nextSlide);
    
    sliderDots.forEach((dot, index) => {
        dot.addEventListener('click', () => showSlide(index));
    });
}

// Add smooth scrolling for anchor links
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
        e.preventDefault();
        
        // Close mobile menu if open
        if (mobileMenu.classList.contains('translate-y-0')) {
            toggleMobileMenu();
        }
        
        const targetId = this.getAttribute('href');
        if (targetId === '#') return;
        
        const targetElement = document.querySelector(targetId);
        if (targetElement) {
            const headerHeight = header.offsetHeight;
            const targetPosition = targetElement.getBoundingClientRect().top + window.pageYOffset;
            
            window.scrollTo({
                top: targetPosition - headerHeight,
                behavior: 'smooth'
            });
        }
    });
});

// Gallery image hover effect
const galleryItems = document.querySelectorAll('.gallery-item');
galleryItems.forEach(item => {
    const img = item.querySelector('img');
    const overlay = item.querySelector('.overlay');
    
    if (img && overlay) {
        item.addEventListener('mouseenter', function() {
            img.classList.add('scale-110');
            overlay.classList.remove('translate-y-full');
            overlay.classList.add('translate-y-0');
        });
        
        item.addEventListener('mouseleave', function() {
            img.classList.remove('scale-110');
            overlay.classList.add('translate-y-full');
            overlay.classList.remove('translate-y-0');
        });
    }
});

// Auto-rotate testimonials
let testimonialInterval;

function startTestimonialRotation() {
    testimonialInterval = setInterval(nextSlide, 5000);
}

function stopTestimonialRotation() {
    clearInterval(testimonialInterval);
}

// Initialize
document.addEventListener('DOMContentLoaded', function() {
    // Initialize testimonial slider
    if (testimonialItems.length > 0) {
        showSlide(0);
        startTestimonialRotation();
        
        // Pause rotation on hover
        const testimonialSlider = document.querySelector('#testimonial-slider');
        if (testimonialSlider) {
            testimonialSlider.addEventListener('mouseenter', stopTestimonialRotation);
            testimonialSlider.addEventListener('mouseleave', startTestimonialRotation);
        }
    }
    
    // Trigger initial animations
    handleScroll();
    
    // Preload images for better performance
    const imagesToPreload = [
        'images/hero-bg.jpg',
        'images/rb-gm91-side.png',
        'images/cta-bg.jpg'
    ];
    
    imagesToPreload.forEach(src => {
        const img = new Image();
        img.src = src;
    });
});

// Lazy load images
document.addEventListener('DOMContentLoaded', function() {
    const lazyImages = document.querySelectorAll('img[data-src]');
    
    if ('IntersectionObserver' in window) {
        const imageObserver = new IntersectionObserver((entries, observer) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    const img = entry.target;
                    img.src = img.dataset.src;
                    img.removeAttribute('data-src');
                    imageObserver.unobserve(img);
                }
            });
        });
        
        lazyImages.forEach(img => {
            imageObserver.observe(img);
        });
    } else {
        // Fallback for browsers that don't support IntersectionObserver
        lazyImages.forEach(img => {
            img.src = img.dataset.src;
            img.removeAttribute('data-src');
        });
    }
});


